svg.script:
(function () {
  var originalGetElementById = document.getElementById.bind(document);
  var originalCreateElement = document.createElement.bind(document);
  var htmlTags = {
    canvas: true, div: true, button: true, input: true, span: true,
    style: true, audio: true, img: true, p: true, label: true, h1: true, h2: true, h3: true, small: true, strong: true, em: true, br: true, section: true, nav: true, ul: true, li: true
  };
  document.createElement = function (tag, options) {
    tag = String(tag).toLowerCase();
    if (htmlTags[tag]) return document.createElementNS('http://www.w3.org/1999/xhtml', tag);
    return originalCreateElement(tag, options);
  };
  function ensureApp() {
    var app = originalGetElementById('app');
    if (app) return app;
    var body = originalGetElementById('svg-body') || document.documentElement;
    app = document.createElementNS('http://www.w3.org/1999/xhtml', 'div');
    app.id = 'app';
    app.style.position = 'fixed';
    app.style.inset = '0';
    body.appendChild(app);
    return app;
  }
  document.getElementById = function (id) {
    return id === 'app' ? ensureApp() : originalGetElementById(id);
  };
  function cleanTextValue(value) {
    return String(value)
      .replace(/ðŸ¥|ðŸ”¥|ðŸ”Š|ðŸ□†|🏆|🔥|🔊|▶/g, '')
      .replace(/Â·|·/g, '-')
      .replace(/Â|â€“|â€”|â–¶/g, '')
      .replace(/\s{2,}/g, ' ')
      .trim();
  }
  function cleanText() {
    var walker = document.createTreeWalker(document, NodeFilter.SHOW_TEXT);
    var node;
    while ((node = walker.nextNode())) {
      var next = cleanTextValue(node.nodeValue);
      if (next !== node.nodeValue) node.nodeValue = next;
    }
    var friendly = originalGetElementById('friendly');
    var mute = originalGetElementById('mute');
    var help = originalGetElementById('help');
    var high = originalGetElementById('highscore');
    if (friendly) friendly.textContent = 'Brisket Mode';
    if (mute) mute.textContent = 'Music';
    if (help) help.textContent = 'Left stick to move - Right stick to spin camera - A to jump - X to dance - Catch kids for brisket';
    if (high && high.previousSibling) high.previousSibling.nodeValue = ' Best ';
  }
  setInterval(cleanText, 500);
  setTimeout(cleanText, 50);
})();
